const API_URL = '/api';

// Helper function to get headers
const getHeaders = () => {
  const token = localStorage.getItem('token');
  return {
    'Content-Type': 'application/json',
    ...(token ? { Authorization: `Bearer ${token}` } : {}),
  };
};

const handleResponse = async (response: Response) => {
  if (response.status === 401) {
    localStorage.removeItem('token');
    // Optional: Redirect to login or dispatch event
    // window.location.href = '/login'; 
    throw new Error('Session expired. Please login again.');
  }

  // Handle empty responses (like 204 No Content)
  if (response.status === 204) {
      return null;
  }

  const contentType = response.headers.get("content-type");
  if (contentType && contentType.indexOf("application/json") !== -1) {
    const data = await response.json();
    if (!response.ok) {
      throw new Error(data.error || data.message || 'API Error');
    }
    return data;
  } else {
    // Check for HTML response (SPA Fallback issue)
    const text = await response.text();
    if (text.trim().startsWith('<!DOCTYPE html>')) {
        throw new Error('Server misconfiguration: API endpoint returned HTML. Please check backend connection.');
    }

    if (!response.ok) {
        throw new Error(text || `API Error: ${response.status} ${response.statusText}`);
    }
    return text; 
  }
};

const request = async (method: string, endpoint: string, body?: any) => {
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), 15000); // 15 second timeout

  const config: RequestInit = {
    method,
    headers: getHeaders(),
    signal: controller.signal,
  };

  if (body) {
    config.body = JSON.stringify(body);
  }

  try {
    const response = await fetch(`${API_URL}${endpoint}`, config);
    clearTimeout(timeoutId);
    return await handleResponse(response);
  } catch (error: any) {
    clearTimeout(timeoutId);
    if (error.name === 'AbortError') {
        throw new Error('Request timed out. Server is taking too long to respond.');
    }
    throw error;
  }
};

const get = (endpoint: string) => request('GET', endpoint);
const post = (endpoint: string, body?: any) => request('POST', endpoint, body);
const put = (endpoint: string, body?: any) => request('PUT', endpoint, body);
const del = (endpoint: string) => request('DELETE', endpoint);

const upload = async (endpoint: string, file: File) => {
    const formData = new FormData();
    formData.append('file', file);
    const token = localStorage.getItem('token');

    const response = await fetch(`${API_URL}${endpoint}`, {
      method: 'POST',
      headers: {
          ...(token ? { Authorization: `Bearer ${token}` } : {}),
      },
      body: formData,
    });
    return handleResponse(response);
};

const download = async (endpoint: string) => {
    const token = localStorage.getItem('token');
    const response = await fetch(`${API_URL}${endpoint}`, {
        method: 'GET',
        headers: {
            ...(token ? { Authorization: `Bearer ${token}` } : {}),
        },
    });

    if (!response.ok) throw new Error('Download failed');

    const blob = await response.blob();
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    // Attempt to extract filename from content-disposition header if available
    const contentDisposition = response.headers.get('Content-Disposition');
    let filename = 'download';
    if (contentDisposition) {
        const matches = /filename="([^"]*)"/.exec(contentDisposition);
        if (matches != null && matches[1]) { 
            filename = matches[1]; 
        }
    }
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    a.remove();
    window.URL.revokeObjectURL(url);
};

